const https = require('https');
const fs = require('fs');

// 读取参数
const argsFile = process.argv[2];
const args = JSON.parse(fs.readFileSync(argsFile, 'utf8'));

const query = args.query || '';
const engineType = args.engine_type || 'Generic';
const timeRange = args.time_range || 'OneWeek';
const maxResults = args.max_results || 5;

// 从环境变量或配置文件获取 API Key
let apiKey = process.env.ALIYUN_IQS_API_KEY;
if (!apiKey) {
  try {
    const envFile = require('path').join(require('os').homedir(), '.alibabacloud', 'iqs', 'env');
    const envContent = fs.readFileSync(envFile, 'utf8');
    const match = envContent.match(/ALIYUN_IQS_API_KEY=(.+)/);
    if (match) {
      apiKey = match[1].trim();
    }
  } catch (e) {
    // 忽略文件读取错误
  }
}

if (!apiKey) {
  console.error('Error: ALIYUN_IQS_API_KEY not found. Please set it in environment or ~/.alibabacloud/iqs/env');
  process.exit(1);
}

// 构建请求
const postData = JSON.stringify({
  query: query,
  engineType: engineType,
  timeRange: timeRange,
  maxResults: maxResults
});

const options = {
  hostname: 'iqs.aliyuncs.com',
  port: 443,
  path: '/api/v1/search',
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'Authorization': `Bearer ${apiKey}`,
    'Content-Length': Buffer.byteLength(postData)
  }
};

const req = https.request(options, (res) => {
  let data = '';

  res.on('data', (chunk) => {
    data += chunk;
  });

  res.on('end', () => {
    try {
      const result = JSON.parse(data);

      if (result.results && result.results.length > 0) {
        // 格式化输出结果
        const formatted = result.results.map((item, index) => {
          return `[${index + 1}] ${item.title}\nURL: ${item.url}\nSummary: ${item.snippet || 'N/A'}\n`;
        }).join('\n');

        console.log(formatted);
      } else {
        console.log('No results found.');
      }
    } catch (e) {
      console.error('Failed to parse response:', data);
      process.exit(1);
    }
  });
});

req.on('error', (e) => {
  console.error(`Request failed: ${e.message}`);
  process.exit(1);
});

req.write(postData);
req.end();
